var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여긴가요? 미나 양이 사는 곳이?","JPN":"ここですか、ミナさんのお住まいは？","ENG":"Is this the place? This is where you live?","TWN":"就是這裡嗎？米娜小姐生活的地方？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そうよ。","ENG":"Yeah.","TWN":"對。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 집까지 바래다 주다니 무슨 일이야?","JPN":"ところで、家まで送ってくれるなんて、どういう風の吹き回しなの？","ENG":"What made you decide to escort me home by the way?","TWN":"不過你竟然會送我回家，這是怎麼回事？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"전엔 그런 적 없었잖아.","JPN":"これまでこんなことなかったじゃない。","ENG":"You never did this before.","TWN":"你以前不是沒做過這種事情嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 이런 것도 다 업무의 연장선상이라고 할 수 있죠.","JPN":"ははっ、こういうのもすべて業務の延長線上といえますからね。","ENG":"Haha. This is all part of the job, really.","TWN":"哈哈，這可以說是工作的延伸吧。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오늘은...... 스승님께서 꼭 집까지 바래다 주라고 당부하셨거든요.","JPN":"今日は……必ず家まで送れと師匠に言われたんです。","ENG":"Because today... the Master specifically asked me to take you home.","TWN":"因為今天……師父交代我一定要把妳送回家。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"처음 이런 일을 겪으면...... 음, 뭐라고 해야 하나?","JPN":"初めてこんなことを経験すると……うーん、何て言えばいいんでしょう。","ENG":"When folks experience this sort of thing for the first time... Hmm... How should I put it?","TWN":"我是第一次經歷這種事……嗯，我應該說些什麼？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇네요. 사고가 나는 경우가 많거든요.","JPN":"そうだ、事故が起こる場合が多いんです。","ENG":"Oh, right. “Accidents” tend to happen.","TWN":"是啊，這次真的發生太多事了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마. 괜찮으니까.","JPN":"心配いらないよ、大丈夫だから。","ENG":"Don't worry. I’m fine.","TWN":"別擔心，我沒事。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜, 길바닥에 쓰러져서 울기라도 할 것 같아?","JPN":"なに、私が道端に倒れ込んで、泣くとでも？","ENG":"You worried I’d plop down in the middle of the street and start bawling?","TWN":"幹嘛，你以為會倒在地上痛哭嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그럴 리가요.","JPN":"はははっ、まさか。","ENG":"Haha, of course not.","TWN":"哈哈，怎麼會呢。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 그런데 혹시 들으셨어요?","JPN":"あ、ところで、聞きましたか？","ENG":"By the way, have you heard?","TWN":"話說回來，米娜小姐妳聽說了嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"서윤 양이 들어 있던 추출기 말인데......","JPN":"シズカさんが入っていた抽出器のことなんですけど……","ENG":"The extractor that Seo Yoon was in...","TWN":"徐芸小姐進入的萃取器……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"작동한 적이 없다고 하더라고요.","JPN":"作動した形跡がないそうです。","ENG":"They say it was never activated.","TWN":"其實並沒有啟動。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 덕분에 서윤 양은 별다른 부상이 없어서 다행이지만요.","JPN":"まあ、おかげでシズカさんは無傷だったので良かったんですけどね。","ENG":"Lucky for her, she got out with hardly a scratch.","TWN":"所以，徐芸小姐沒受什麼傷，可以說是萬幸吧。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"고장이었던 건지...... 실수인 건지......","JPN":"故障だったのか……それとも、ミスだったのか……","ENG":"I’m not sure if it was malfunctioning... or a mistake.","TWN":"是萃取器故障了呢……還是操作失誤了呢……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그분, 혹시 처음부터 그럴 생각이 없었던 건 아닐까요?","JPN":"あの人はもしかしたら、初めからそのつもりはなかったのではでしょうか。","ENG":"Maybe your friend never intended to turn it on in the first place?","TWN":"或者是，娜拉小姐從一開始就不打算這麼做呢？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"관심없어. 죽은 사람 사정 따윈.","JPN":"興味ないよ。死んだ人の事情なんて。","ENG":"Who cares. She's dead now.","TWN":"我對死人的事情沒興趣。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};